'use strict';
import React, {Component} from 'react';
import mockData from './data.js';
const Canvas = require('../../../index.js').TreeCanvas;
require('./index.less');

class MindMapNew extends Component {
  constructor() {
    super();
  }
  componentDidMount() {
    let root = document.getElementById('dag-canvas');
    this.canvas = new Canvas({
      root: root,
      disLinkable: true, // 可删除连线
      linkable: true,    // 可连线
      draggable: true,   // 可拖动
      zoomable: true,    // 可放大
      moveable: true,    // 可平移
      theme: {
        edge: {
          type: 'AdvancedBezier',
        }
      },
      layout: {
        type: 'mindmap',
        options: {
          direction: 'H',
          getSide(d) {
            return d.data.side || 'right';
          },
          getHeight(d) {
            return 10;
          },
          getWidth(d) {
            return 40;
          },
          getHGap(d) {
            return 50;
          },
          getVGap(d) {
            return 20;
          },
        }
      }
    });
    this.canvas.draw(mockData, {}, () => {
      this.canvas.focusCenterWithAnimate();
    }
    );
    this.canvas.on('events', (data) => {
      console.log(data);
    });
  }
  render() {
    return (
      <div className='mind-map-new'>
        <div className="compactBoxTree-canvas" id="dag-canvas">
        </div>
      </div>
    );
  }
}

module.exports = MindMapNew;

@import 'theme.less'; 
.mind-map-new {
  width: 100%;
  height: 100%;
  text-align: center;
  background: #fff;
  .compactBoxTree-canvas {
    width: 100%;
    height: 100%;
    .butterfly-wrapper {
      #Root {
        border-radius: 10px;
        font-weight: 500;
        border: 1px solid #d9d9d9;
        padding: 8px 16px;
        .iconfont {
         background: #9254DE; 
        }
        .title {
          color: #333;
        }
      }
      .mind-map-node {
        position: absolute;
        background: #fff;
        border: 1px solid #d9d9d9;
        border-radius: 10px;
        padding: 8px 8px;
        display: flex;
        justify-content: space-between;
        .iconfont {
          background: #40A9FF;
          padding: 6px;
          border-radius: 50%;
        }
        .title {
          color: #333;
        }
      }
    }
  }
}

'use strict';

const Node = require('../../../index.js').TreeNode;
const $ = require('jquery');

class BaseNode extends Node {
  constructor(opts) {
    super(opts);
  }

  draw = (opts) => {
    console.log('opts: ', opts);
    let container = $('<div class="mind-map-node"></div>')
      .css('top', opts.top)
      .css('left', opts.left)
      .attr('id', opts.id);
    let titleDom = $(`
    <div class="title">
      <i class="iconfont">${opts.id === 'Root' ? '&#xe8b3;' : '&#xe6ff;'}</i>
      ${opts.options.title}
    <div>`);

    container.append(titleDom);

    return container[0];
  }
}

module.exports = BaseNode;

